SELECT AVG(total) AS average_amount_spent_per_invoice
FROM invoice
WHERE billing_state = 'CA';

SELECT COUNT(*) AS tracks_above_average_price
FROM track
WHERE unit_price > (SELECT AVG(unit_price) FROM track);

SELECT COUNT(*) AS unknown_composer_count
FROM track
WHERE composer = 'Unknown';

SELECT employee_id, first_name, last_name, hire_date
FROM employee
WHERE hire_date < '2010-01-01';
